    {id:"4-92",type:"vocabulary",q:"What does 'die Kinderabteilung' mean?",opts:["The toy section","The children's section","The school supplies","The playground"],ans:1,exp_en:"'die Kinderabteilung' = children's department/section in a store.",exp_de:"'die Kinderabteilung' = Abteilung für Kinder im Kaufhaus."},
    {id:"4-93",type:"sentence",q:"Which correctly declines: 'I'm buying my friend a new bag.' (Dativ/Akkusativ)",opts:["Ich kaufe meiner Freundin eine neue Tasche.","Ich kaufe meine Freundin eine neue Tasche.","Ich kaufe meiner Freundin einen neue Tasche.","Ich kaufe meiner Freundin eine neuen Tasche."],ans:0,exp_en:"'meiner Freundin' = Dativ feminine. 'eine neue Tasche' = Akkusativ feminine.",exp_de:"'meiner Freundin' = Dativ feminin. 'eine neue Tasche' = Akkusativ feminin."},
    {id:"4-94",type:"vocabulary",q:"What does 'die Kette' mean?",opts:["The bracelet","The necklace/chain","The ring","The earring"],ans:1,exp_en:"'die Kette' = necklace or chain.",exp_de:"'die Kette' = Kette."},
    {id:"4-95",type:"fill",q:"Ich brauche ein___ neu___ Gürtel. (Akkusativ, maskulin)",opts:["en / en","e / e","— / en","es / en"],ans:0,exp_en:"Masculine Akkusativ: 'einen' + adjective '-en'. 'der Gürtel' is masculine.",exp_de:"Maskulin Akkusativ: 'einen' + Adjektiv '-en'. 'der Gürtel' ist maskulin."},
    {id:"4-96",type:"vocabulary",q:"What does 'die Branche' mean?",opts:["The brand","The industry/sector","The department","The career"],ans:1,exp_en:"'die Branche' = industry, sector (of business).",exp_de:"'die Branche' = Wirtschaftszweig, Sektor."},
    {id:"4-97",type:"sentence",q:"Which question correctly asks 'What kind of shoes?' (Akkusativ Plural)",opts:["Was für Schuhe suchst du?","Was für einen Schuhe suchst du?","Was für eine Schuhe suchst du?","Was für ein Schuhe suchst du?"],ans:0,exp_en:"Plural with 'Was für' takes no article: 'Was für Schuhe?'",exp_de:"Plural mit 'Was für' ohne Artikel: 'Was für Schuhe?'"},
    {id:"4-98",type:"vocabulary",q:"What does 'das Vorstellungsgespräch' mean?",opts:["The introduction","The job interview","The presentation","The conversation"],ans:1,exp_en:"'das Vorstellungsgespräch' = job interview.",exp_de:"'das Vorstellungsgespräch' = Bewerbungsgespräch."},
    {id:"4-99",type:"fill",q:"Welch___ Farbe gefällt dir am besten? (Nominativ, feminin)",opts:["e","er","es","en"],ans:0,exp_en:"'welche' (feminine Nominativ) + 'Farbe gefällt dir?'",exp_de:"'welche' (feminin Nominativ) + 'Farbe gefällt dir?'"},
    {id:"4-100",type:"sentence",q:"Choose the fully correct sentence about clothing shopping:",opts:["Ich probiere einen blauen Mantel an, aber er passt mir nicht.","Ich probiere ein blauer Mantel an, aber er passt mir nicht.","Ich probiere einen blaue Mantel an, aber er passt mich nicht.","Ich probiere ein blauen Mantel an, aber er passt mir nicht."],ans:0,exp_en:"Masculine Akkusativ 'einen blauen Mantel' + 'passen' takes Dativ 'mir'.",exp_de:"Maskulin Akkusativ 'einen blauen Mantel' + 'passen' braucht Dativ 'mir'."}
