    {id:"8-91",type:"fill",q:"Der Zebrastreifen ist ___ der Ampel. (next to — position)",opts:["neben","an","gegenüber","über"],ans:0,exp_en:"'neben + Dativ' = next to (position).",exp_de:"'neben + Dativ' = neben (Position)."},
    {id:"8-92",type:"vocabulary",q:"What does 'die Seilbahn' mean?",opts:["The train","The cable car","The bus","The ferry"],ans:1,exp_en:"'die Seilbahn' = cable car.",exp_de:"'die Seilbahn' = Seilbahn."},
    {id:"8-93",type:"sentence",q:"Which says 'We met at the entrance'?",opts:["Wir haben uns am Eingang getroffen.","Wir haben uns an den Eingang getroffen.","Wir haben uns ins Eingang getroffen.","Wir haben uns im Eingang getroffen."],ans:0,exp_en:"'am Eingang' = an + dem (Dativ, masc.) = at the entrance.",exp_de:"'am Eingang' = an + dem (Dativ, mask.) = am Eingang."},
    {id:"8-94",type:"vocabulary",query:"What does 'der Taxistand' mean?",q:"What does 'der Taxistand' mean?",opts:["The bus stop","The taxi rank","The car park","The train stop"],ans:1,exp_en:"'der Taxistand' = taxi rank.",exp_de:"'der Taxistand' = Taxistand."},
    {id:"8-95",type:"fill",q:"Geh ___ den Zebrastreifen ___ die andere Seite. (across to)",opts:["über / auf","durch / an","an / auf","über / in"],ans:0,exp_en:"'über + den' (Akkusativ masc.) + 'auf die andere Seite' (Akkusativ).",exp_de:"'über + den' (Akkusativ mask.) + 'auf die andere Seite' (Akkusativ)."},
    {id:"8-96",type:"vocabulary",q:"What does 'das Ticket' mean in a tourism context?",opts:["The programme","The ticket (entry/transport)","The itinerary","The booking reference"],ans:1,exp_en:"'das Ticket' = ticket (for entry or transport).",exp_de:"'das Ticket' = Ticket (Eintrittskarte oder Fahrkarte)."},
    {id:"8-97",type:"sentence",q:"Which is the correct formal direction sentence?",opts:["Gehen Sie durch das Tor und dann geradeaus bis zum Museum.","Gehen Sie durch das Tor und dann geradeaus bis das Museum.","Gehen Sie durch das Tor und dann geradeaus bis zu Museum.","Gehen Sie durch das Tor und dann geradeaus bis dem Museum."],ans:0,exp_en:"'durch das Tor' (Akkusativ neut.) + 'bis zum Museum' = bis zu + dem (Dativ neut.).",exp_de:"'durch das Tor' (Akkusativ neutrum) + 'bis zum Museum' = bis zu + dem (Dativ neutrum)."},
    {id:"8-98",type:"vocabulary",q:"What does 'die Touristeninformation' mean?",opts:["The tourist tax","The tourist information office","The tour bus","The sightseeing map"],ans:1,exp_en:"'die Touristeninformation' = tourist information office.",exp_de:"'die Touristeninformation' = Touristeninformation."},
    {id:"8-99",type:"fill",q:"Unser Hotel liegt direkt ___ dem Tiergarten. (opposite)",opts:["gegenüber","neben","über","durch"],ans:0,exp_en:"'gegenüber + Dativ' = opposite.",exp_de:"'gegenüber + Dativ' = gegenüber."},
    {id:"8-100",type:"sentence",q:"Choose the fully correct set of directions:",opts:["Gehen Sie durch den Park, über die Brücke und dann bis zur Touristeninformation gegenüber dem Rathaus.","Gehen Sie durch dem Park, über der Brücke und dann bis die Touristeninformation gegenüber das Rathaus.","Gehen Sie durch den Park, über die Brücke und dann bis zu Touristeninformation gegenüber dem Rathaus.","Gehen Sie durch den Park, über der Brücke und dann bis zur Touristeninformation gegenüber dem Rathaus."],ans:0,exp_en:"'durch + den' (Akk.masc.) + 'über + die' (Akk.fem.) + 'bis zur' (Dat.fem.) + 'gegenüber + dem' (Dat.neut.).",exp_de:"'durch + den' (Akk.mask.) + 'über + die' (Akk.fem.) + 'bis zur' (Dat.fem.) + 'gegenüber + dem' (Dat.neutrum)."}
